#!/usr/bin/env python3
# C-supplychain: audit CI workflows for unpinned actions, pull_request_target + checkout
# of untrusted ref, and self-hosted-runner exposure. READ-ONLY static config audit.
import os, re, sys, glob
try:
    import yaml
except ImportError:
    print('install pyyaml: pip install pyyaml'); sys.exit(2)

SAMPLE = '''name: ci
on: [pull_request_target]
jobs:
  build:
    runs-on: [self-hosted, linux]
    steps:
      - uses: actions/checkout@v4
        with: {ref: "${{ github.event.pull_request.head.sha }}"}
      - uses: some-org/build-action@main
      - run: make release
'''

def load_docs():
    d = os.environ.get('WF_DIR')
    if d:
        for p in glob.glob(os.path.join(d,'*.y*ml')):
            yield p, open(p).read()
    else:
        yield '<sample>', SAMPLE

SHA = re.compile(r'@[0-9a-f]{40}$')
findings = []
for path, text in load_docs():
    try: doc = yaml.safe_load(text)
    except Exception: continue
    on = doc.get(True, doc.get('on'))
    danger_trigger = 'pull_request_target' in str(on)
    for job in (doc.get('jobs') or {}).values():
        runson = str(job.get('runs-on',''))
        for st in job.get('steps') or []:
            uses = st.get('uses','')
            if uses and '@' in uses and not SHA.search(uses) and not uses.startswith('./'):
                findings.append((path, f'unpinned action (not SHA): {uses}'))
            ref = str(st.get('with',{}).get('ref','')) if isinstance(st.get('with'),dict) else ''
            if danger_trigger and ('pull_request.head' in ref):
                findings.append((path, 'pull_request_target checks out attacker-controlled head ref -> secret-exposing code exec'))
        if 'self-hosted' in runson:
            findings.append((path, f'self-hosted runner ({runson}) -> persistent compromise risk if public repo'))

if findings:
    print('VULNERABLE: CI supply-chain seams found:')
    for p,f in findings: print(f'   - [{p}] {f}')
    print('Fix: pin actions to full commit SHA; never checkout PR head under pull_request_target; ephemeral runners.')
    sys.exit(0)
print('PASS: actions pinned, no risky trigger/checkout, no self-hosted exposure.')
sys.exit(1)

